    # === REGULAR (1-25) ===
    {"id":"r01","tag":"Regular","name":"Chicken Schnitzel","description":"Crispy crumbed chicken with lemon","image":"https://images.unsplash.com/photo-1632778149955-e80f8ceca2e8?w=400&h=300&fit=crop&q=80","emoji":"\U0001f357","time":"35 min","steps":["Pound chicken breasts to even thickness.","Set up 3 bowls: flour, beaten eggs, breadcrumbs.","Coat each breast: flour, egg, breadcrumbs.","Heat oil in a large pan over medium-high heat.","Fry schnitzels 3-4 min each side until golden.","Drain on paper towels, serve with lemon wedges."],"ingredients":[{"name":"Chicken Breast","quantity":2,"category":"Meat"},{"name":"Breadcrumbs","quantity":1,"category":"Pantry"},{"name":"Eggs","quantity":2,"category":"Dairy"},{"name":"Flour","quantity":1,"category":"Pantry"},{"name":"Lemon","quantity":1,"category":"Produce"},{"name":"Oil","quantity":1,"category":"Pantry"}]},
    {"id":"r02","tag":"Regular","name":"Spaghetti Bolognese","description":"Classic beef mince pasta with rich tomato sauce","image":"https://images.unsplash.com/photo-1622973536968-3ead9e780960?w=400&h=300&fit=crop&q=80","emoji":"\U0001f35d","time":"40 min","steps":["Heat olive oil, saut\u00e9 diced onion and garlic until soft.","Add beef mince, cook until browned.","Grate in carrot, add canned tomatoes, stir well.","Simmer on low for 20 min, season to taste.","Cook spaghetti in salted boiling water.","Serve sauce over pasta, top with parmesan."],"ingredients":[{"name":"Beef Mince","quantity":1,"category":"Meat"},{"name":"Spaghetti","quantity":1,"category":"Pantry"},{"name":"Canned Tomatoes","quantity":1,"category":"Pantry"},{"name":"Onion","quantity":1,"category":"Produce"},{"name":"Garlic","quantity":2,"category":"Produce"},{"name":"Carrot","quantity":1,"category":"Produce"},{"name":"Parmesan","quantity":1,"category":"Dairy"}]},
    {"id":"r03","tag":"Regular","name":"Chicken Stir Fry","description":"Quick veggie & chicken stir fry with soy","image":"https://images.unsplash.com/photo-1512058564366-18510be2db19?w=400&h=300&fit=crop&q=80","emoji":"\U0001f958","time":"20 min","steps":["Slice chicken thigh into strips.","Chop capsicum, broccoli, carrot into bite-sized pieces.","Heat oil in a wok over high heat.","Stir-fry chicken 4-5 min, set aside.","Stir-fry vegetables 3 min, add garlic and ginger.","Return chicken, add soy sauce, toss and serve over rice."],"ingredients":[{"name":"Chicken Thigh","quantity":2,"category":"Meat"},{"name":"Capsicum","quantity":1,"category":"Produce"},{"name":"Broccoli","quantity":1,"category":"Produce"},{"name":"Carrot","quantity":1,"category":"Produce"},{"name":"Soy Sauce","quantity":1,"category":"Pantry"},{"name":"Rice","quantity":1,"category":"Pantry"},{"name":"Garlic","quantity":2,"category":"Produce"}]},
    {"id":"r04","tag":"Regular","name":"Fish & Chips","description":"Crispy battered fish with oven chips","image":"https://images.unsplash.com/photo-1534080564583-6be75777b70a?w=400&h=300&fit=crop&q=80","emoji":"\U0001f35f","time":"45 min","steps":["Cut potatoes into chips, toss with oil and salt.","Bake chips at 220\u00b0C for 30 min, turning halfway.","Mix flour with sparkling water to make batter.","Coat fish fillets in batter.","Deep-fry or pan-fry fish 4 min each side until golden.","Serve with lemon wedges and tartare sauce."],"ingredients":[{"name":"Fish Fillets","quantity":2,"category":"Meat"},{"name":"Potatoes","quantity":4,"category":"Produce"},{"name":"Flour","quantity":1,"category":"Pantry"},{"name":"Lemon","quantity":1,"category":"Produce"},{"name":"Oil","quantity":1,"category":"Pantry"}]},
    {"id":"r05","tag":"Regular","name":"Beef Tacos","description":"Seasoned beef tacos with fresh toppings","image":"https://images.unsplash.com/photo-1565299585323-38d6b0865b47?w=400&h=300&fit=crop&q=80","emoji":"\U0001f32e","time":"25 min","steps":["Brown beef mince in a pan, drain excess fat.","Add taco seasoning and a splash of water, simmer 5 min.","Warm taco shells in the oven.","Dice tomato, shred lettuce, grate cheese.","Fill shells with beef, top with salad and sour cream.","Serve immediately."],"ingredients":[{"name":"Beef Mince","quantity":1,"category":"Meat"},{"name":"Taco Shells","quantity":1,"category":"Pantry"},{"name":"Lettuce","quantity":1,"category":"Produce"},{"name":"Tomato","quantity":2,"category":"Produce"},{"name":"Cheese","quantity":1,"category":"Dairy"},{"name":"Sour Cream","quantity":1,"category":"Dairy"}]},
    {"id":"r06","tag":"Regular","name":"Baked Salmon","description":"Oven-baked salmon with roasted vegetables","image":"https://images.unsplash.com/photo-1467003909585-2f8a72700288?w=400&h=300&fit=crop&q=80","emoji":"\U0001f969","time":"35 min","steps":["Preheat oven to 200\u00b0C.","Chop kumara, broccoli, capsicum into chunks.","Toss vegetables with olive oil on a tray.","Place salmon fillets on top, squeeze lemon over.","Season with salt and pepper.","Bake 20-25 min until salmon flakes easily."],"ingredients":[{"name":"Salmon Fillets","quantity":2,"category":"Meat"},{"name":"Kumara","quantity":2,"category":"Produce"},{"name":"Broccoli","quantity":1,"category":"Produce"},{"name":"Capsicum","quantity":1,"category":"Produce"},{"name":"Olive Oil","quantity":1,"category":"Pantry"},{"name":"Lemon","quantity":1,"category":"Produce"}]},
