    {"id":"r09","tag":"Regular","name":"Loaded Nachos","description":"Corn chips with beef, cheese & guac","image":"https://images.unsplash.com/photo-1513456852971-30c0b8199d4d?w=400&h=300&fit=crop&q=80","emoji":"\U0001f9c0","time":"25 min","steps":["Brown beef mince with taco seasoning.","Spread corn chips on an oven tray.","Top with beef, grated cheese, and salsa.","Bake at 200\u00b0C for 10 min until cheese melts.","Mash avocado with lime for guacamole.","Top nachos with guac and sour cream."],"ingredients":[{"name":"Corn Chips","quantity":1,"category":"Snacks"},{"name":"Beef Mince","quantity":1,"category":"Meat"},{"name":"Cheese","quantity":1,"category":"Dairy"},{"name":"Avocado","quantity":1,"category":"Produce"},{"name":"Tomato","quantity":2,"category":"Produce"},{"name":"Sour Cream","quantity":1,"category":"Dairy"}]},
    {"id":"r10","tag":"Regular","name":"Egg Fried Rice","description":"Quick fried rice with vegetables and soy","image":"https://images.unsplash.com/photo-1603133872878-684f208fb84b?w=400&h=300&fit=crop&q=80","emoji":"\U0001f35a","time":"15 min","steps":["Cook rice and let it cool (or use day-old rice).","Heat oil in a wok over high heat.","Scramble eggs, push to one side.","Add diced carrot, peas, and spring onion.","Add rice, toss everything together.","Season with soy sauce and serve."],"ingredients":[{"name":"Rice","quantity":1,"category":"Pantry"},{"name":"Eggs","quantity":3,"category":"Dairy"},{"name":"Frozen Peas","quantity":1,"category":"Frozen"},{"name":"Carrot","quantity":1,"category":"Produce"},{"name":"Soy Sauce","quantity":1,"category":"Pantry"},{"name":"Spring Onion","quantity":1,"category":"Produce"}]},
    {"id":"r11","tag":"Regular","name":"Homemade Burgers","description":"Juicy beef burgers with all the fixings","image":"https://images.unsplash.com/photo-1568901346375-23c9450c58cd?w=400&h=300&fit=crop&q=80","emoji":"\U0001f354","time":"30 min","steps":["Mix beef mince with salt, pepper, and onion powder.","Form into 2 patties slightly larger than the buns.","Cook patties on high heat 4 min each side.","Toast burger buns lightly.","Layer lettuce, patty, cheese, tomato, and sauce.","Serve with chips or salad."],"ingredients":[{"name":"Beef Mince","quantity":1,"category":"Meat"},{"name":"Burger Buns","quantity":1,"category":"Bakery"},{"name":"Lettuce","quantity":1,"category":"Produce"},{"name":"Tomato","quantity":1,"category":"Produce"},{"name":"Cheese","quantity":1,"category":"Dairy"},{"name":"Tomato Sauce","quantity":1,"category":"Pantry"}]},
    {"id":"r12","tag":"Regular","name":"Lamb Chops & Mash","description":"Pan-seared lamb chops with creamy mash","image":"https://images.unsplash.com/photo-1514516345957-556ca7d90a29?w=400&h=300&fit=crop&q=80","emoji":"\U0001f969","time":"35 min","steps":["Boil potatoes until soft, about 15 min.","Season lamb chops with salt, pepper, and rosemary.","Sear chops in a hot pan 3-4 min each side.","Mash potatoes with butter, cream, and garlic.","Rest chops for 3 min before serving.","Plate mash and chops together."],"ingredients":[{"name":"Lamb Chops","quantity":4,"category":"Meat"},{"name":"Potatoes","quantity":4,"category":"Produce"},{"name":"Butter","quantity":1,"category":"Dairy"},{"name":"Cream","quantity":1,"category":"Dairy"},{"name":"Rosemary","quantity":1,"category":"Produce"},{"name":"Garlic","quantity":2,"category":"Produce"}]},
    {"id":"r13","tag":"Regular","name":"Chicken Pot Pie","description":"Creamy chicken filling with puff pastry top","image":"https://images.unsplash.com/photo-1621996346565-e3dbc646d9a9?w=400&h=300&fit=crop&q=80","emoji":"\U0001f967","time":"50 min","steps":["Dice chicken and cook in a pot until sealed.","Add diced carrot, onion, and peas.","Pour in cream and simmer 10 min until thick.","Pour filling into an oven-safe dish.","Top with puff pastry, brush with egg wash.","Bake at 200\u00b0C for 20 min until golden."],"ingredients":[{"name":"Chicken Breast","quantity":2,"category":"Meat"},{"name":"Puff Pastry","quantity":1,"category":"Frozen"},{"name":"Carrot","quantity":1,"category":"Produce"},{"name":"Frozen Peas","quantity":1,"category":"Frozen"},{"name":"Cream","quantity":1,"category":"Dairy"},{"name":"Onion","quantity":1,"category":"Produce"}]},
    {"id":"r14","tag":"Regular","name":"Meatballs & Pasta","description":"Italian-style meatballs in tomato sauce","image":"https://images.unsplash.com/photo-1595295333158-4742f28fbd85?w=400&h=300&fit=crop&q=80","emoji":"\U0001f35d","time":"40 min","steps":["Mix mince with breadcrumbs, egg, garlic, salt, pepper.","Roll into golf-ball sized meatballs.","Brown meatballs in a pan, set aside.","Add canned tomatoes to the pan, simmer 5 min.","Return meatballs, simmer 15 min in sauce.","Serve over cooked penne with parmesan."],"ingredients":[{"name":"Beef Mince","quantity":1,"category":"Meat"},{"name":"Penne","quantity":1,"category":"Pantry"},{"name":"Canned Tomatoes","quantity":1,"category":"Pantry"},{"name":"Breadcrumbs","quantity":1,"category":"Pantry"},{"name":"Eggs","quantity":1,"category":"Dairy"},{"name":"Parmesan","quantity":1,"category":"Dairy"},{"name":"Garlic","quantity":2,"category":"Produce"}]},
    {"id":"r15","tag":"Regular","name":"Teriyaki Chicken","description":"Glazed chicken thighs with steamed rice","image":"https://images.unsplash.com/photo-1527477396000-e27163b481c2?w=400&h=300&fit=crop&q=80","emoji":"\U0001f357","time":"30 min","steps":["Mix soy sauce, honey, garlic, and ginger for glaze.","Sear chicken thighs skin-side down for 5 min.","Flip, pour glaze over, cover and cook 15 min.","Steam rice and blanch broccoli.","Slice chicken, drizzle with remaining glaze.","Serve over rice with broccoli."],"ingredients":[{"name":"Chicken Thigh","quantity":2,"category":"Meat"},{"name":"Soy Sauce","quantity":1,"category":"Pantry"},{"name":"Honey","quantity":1,"category":"Pantry"},{"name":"Rice","quantity":1,"category":"Pantry"},{"name":"Ginger","quantity":1,"category":"Produce"},{"name":"Garlic","quantity":2,"category":"Produce"},{"name":"Broccoli","quantity":1,"category":"Produce"}]},
    {"id":"r16","tag":"Regular","name":"Pork Chops & Applesauce","description":"Pan-fried pork chops with apple compote","image":"https://images.unsplash.com/photo-1588168333986-5078d3ae3976?w=400&h=300&fit=crop&q=80","emoji":"\U0001f969","time":"30 min","steps":["Peel and dice apples, simmer with sugar and water until soft.","Mash into a chunky applesauce.","Season pork chops with salt and pepper.","Pan-fry in butter 5 min each side.","Boil and mash potatoes as a side.","Serve chops with applesauce and mash."],"ingredients":[{"name":"Pork Chops","quantity":2,"category":"Meat"},{"name":"Apple","quantity":2,"category":"Produce"},{"name":"Butter","quantity":1,"category":"Dairy"},{"name":"Sugar","quantity":1,"category":"Pantry"},{"name":"Potatoes","quantity":3,"category":"Produce"}]},
    {"id":"r17","tag":"Regular","name":"Sausage Tray Bake","description":"Sausages with roasted veggies on one tray","image":"https://images.unsplash.com/photo-1551782450-a2132b4ba21d?w=400&h=300&fit=crop&q=80","emoji":"\U0001f32d","time":"40 min","steps":["Preheat oven to 200\u00b0C.","Chop potatoes, kumara, capsicum, and onion.","Toss veg with olive oil on a large tray.","Nestle sausages among the vegetables.","Roast 35-40 min, turning sausages halfway.","Serve straight from the tray."],"ingredients":[{"name":"Sausages","quantity":4,"category":"Meat"},{"name":"Potatoes","quantity":3,"category":"Produce"},{"name":"Capsicum","quantity":1,"category":"Produce"},{"name":"Onion","quantity":1,"category":"Produce"},{"name":"Olive Oil","quantity":1,"category":"Pantry"},{"name":"Kumara","quantity":1,"category":"Produce"}]},
    {"id":"r18","tag":"Regular","name":"Beef Stew","description":"Hearty slow-cooked beef and vegetable stew","image":"https://images.unsplash.com/photo-1534939561126-855b8675edd7?w=400&h=300&fit=crop&q=80","emoji":"\U0001f958","time":"90 min","steps":["Cut beef into cubes, toss with flour.","Brown beef in batches in a hot pot.","Add diced onion, carrot, and potatoes.","Pour in beef stock, bring to a boil.","Reduce heat, cover and simmer for 1 hour.","Season to taste and serve with crusty bread."],"ingredients":[{"name":"Beef Chuck","quantity":1,"category":"Meat"},{"name":"Potatoes","quantity":3,"category":"Produce"},{"name":"Carrot","quantity":2,"category":"Produce"},{"name":"Onion","quantity":1,"category":"Produce"},{"name":"Beef Stock","quantity":1,"category":"Pantry"},{"name":"Flour","quantity":1,"category":"Pantry"}]},
    {"id":"r19","tag":"Regular","name":"Mac & Cheese","description":"Creamy baked macaroni and cheese","image":"https://images.unsplash.com/photo-1543339494-b4cd4f7ba686?w=400&h=300&fit=crop&q=80","emoji":"\U0001f9c0","time":"35 min","steps":["Cook macaroni until al dente, drain.","Melt butter, stir in flour to make a roux.","Gradually add milk, stirring until thick.","Add grated cheese, stir until melted.","Mix in macaroni, pour into a baking dish.","Top with breadcrumbs, bake at 190\u00b0C for 15 min."],"ingredients":[{"name":"Macaroni","quantity":1,"category":"Pantry"},{"name":"Cheese","quantity":2,"category":"Dairy"},{"name":"Milk","quantity":1,"category":"Dairy"},{"name":"Butter","quantity":1,"category":"Dairy"},{"name":"Flour","quantity":1,"category":"Pantry"},{"name":"Breadcrumbs","quantity":1,"category":"Pantry"}]},
    {"id":"r20","tag":"Regular","name":"Honey Soy Chicken","description":"Sticky glazed chicken drums with rice","image":"https://images.unsplash.com/photo-1598103442097-8b74394b95c6?w=400&h=300&fit=crop&q=80","emoji":"\U0001f357","time":"45 min","steps":["Mix honey, soy sauce, and minced garlic.","Place drumsticks in a baking dish.","Pour sauce over, marinate 10 min if time allows.","Bake at 200\u00b0C for 35 min, basting twice.","Steam rice and blanch broccoli.","Serve drumsticks over rice with pan juices."],"ingredients":[{"name":"Chicken Drumsticks","quantity":4,"category":"Meat"},{"name":"Honey","quantity":1,"category":"Pantry"},{"name":"Soy Sauce","quantity":1,"category":"Pantry"},{"name":"Garlic","quantity":2,"category":"Produce"},{"name":"Rice","quantity":1,"category":"Pantry"},{"name":"Broccoli","quantity":1,"category":"Produce"}]},
