    {"id":"r22","tag":"Regular","name":"Pork Ramen","description":"Quick noodle soup with pork and egg","image":"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&h=300&fit=crop&q=80","emoji":"\U0001f35c","time":"25 min","steps":["Soft-boil eggs (6 min), peel and halve.","Slice pork into thin strips.","Simmer chicken stock with soy sauce and ginger.","Cook noodles according to packet.","Sear pork strips in a hot pan.","Assemble: noodles, broth, pork, egg, spring onion."],"ingredients":[{"name":"Pork Strips","quantity":1,"category":"Meat"},{"name":"Ramen Noodles","quantity":1,"category":"Pantry"},{"name":"Eggs","quantity":2,"category":"Dairy"},{"name":"Chicken Stock","quantity":1,"category":"Pantry"},{"name":"Soy Sauce","quantity":1,"category":"Pantry"},{"name":"Spring Onion","quantity":1,"category":"Produce"},{"name":"Ginger","quantity":1,"category":"Produce"}]},
