    {"id":"r26","tag":"Regular","name":"Chicken Fried Rice","description":"Leftover rice stir-fried with chicken and veg","image":"https://images.unsplash.com/photo-1603133872878-684f208fb84b?w=400&h=300&fit=crop&q=80","emoji":"\U0001f35a","time":"15 min","steps":["Dice chicken, stir-fry in oil until cooked.","Push to side, scramble eggs in same pan.","Add cold rice, peas, and diced carrot.","Toss everything together over high heat.","Season with soy sauce.","Garnish with spring onion."],"ingredients":[{"name":"Chicken Breast","quantity":1,"category":"Meat"},{"name":"Rice","quantity":1,"category":"Pantry"},{"name":"Eggs","quantity":2,"category":"Dairy"},{"name":"Frozen Peas","quantity":1,"category":"Frozen"},{"name":"Soy Sauce","quantity":1,"category":"Pantry"},{"name":"Spring Onion","quantity":1,"category":"Produce"}]},
