    {"id":"r35","tag":"Regular","name":"Tuna Pasta Bake","description":"Creamy tuna and pasta baked with cheese","image":"https://images.unsplash.com/photo-1574894709920-11b28e7367e3?w=400&h=300&fit=crop&q=80","emoji":"\U0001f35d","time":"35 min","steps":["Cook pasta until al dente.","Mix canned tuna, cream, and peas.","Combine with pasta in a baking dish.","Top with grated cheese.","Bake at 190\u00b0C for 15 min until golden.","Serve with a green salad."],"ingredients":[{"name":"Penne","quantity":1,"category":"Pantry"},{"name":"Canned Tuna","quantity":2,"category":"Pantry"},{"name":"Cream","quantity":1,"category":"Dairy"},{"name":"Frozen Peas","quantity":1,"category":"Frozen"},{"name":"Cheese","quantity":1,"category":"Dairy"}]},
    {"id":"r36","tag":"Regular","name":"Schnitzel Burger","description":"Crumbed chicken in a bun with aioli","image":"https://images.unsplash.com/photo-1568901346375-23c9450c58cd?w=400&h=300&fit=crop&q=80","emoji":"\U0001f354","time":"30 min","steps":["Pound chicken breast flat.","Crumb with flour, egg, and breadcrumbs.","Pan-fry until golden and cooked through.","Toast burger buns.","Layer lettuce, schnitzel, tomato, and aioli.","Serve with chips."],"ingredients":[{"name":"Chicken Breast","quantity":2,"category":"Meat"},{"name":"Burger Buns","quantity":1,"category":"Bakery"},{"name":"Breadcrumbs","quantity":1,"category":"Pantry"},{"name":"Eggs","quantity":1,"category":"Dairy"},{"name":"Lettuce","quantity":1,"category":"Produce"},{"name":"Mayonnaise","quantity":1,"category":"Pantry"}]},
    {"id":"r37","tag":"Regular","name":"Beef & Broccoli","description":"Chinese-style beef with broccoli in oyster sauce","image":"https://images.unsplash.com/photo-1512058564366-18510be2db19?w=400&h=300&fit=crop&q=80","emoji":"\U0001f966","time":"20 min","steps":["Slice beef thinly against the grain.","Stir-fry beef in hot oil 2 min, set aside.","Stir-fry broccoli florets 3 min.","Mix soy sauce, oyster sauce, and garlic.","Return beef, pour sauce over, toss.","Serve over steamed rice."],"ingredients":[{"name":"Beef Strips","quantity":1,"category":"Meat"},{"name":"Broccoli","quantity":2,"category":"Produce"},{"name":"Soy Sauce","quantity":1,"category":"Pantry"},{"name":"Garlic","quantity":2,"category":"Produce"},{"name":"Rice","quantity":1,"category":"Pantry"},{"name":"Oil","quantity":1,"category":"Pantry"}]},
    {"id":"r38","tag":"Regular","name":"Lamb Kebabs","description":"Marinated lamb skewers with tzatziki","image":"https://images.unsplash.com/photo-1529006557810-274b9b2fc783?w=400&h=300&fit=crop&q=80","emoji":"\U0001f356","time":"25 min","steps":["Cube lamb, marinate in olive oil, lemon, garlic, oregano.","Thread onto skewers with capsicum and onion.","Grill 4-5 min each side.","Mix yoghurt with cucumber and mint for tzatziki.","Warm flatbread.","Serve kebabs in flatbread with tzatziki."],"ingredients":[{"name":"Lamb Leg","quantity":1,"category":"Meat"},{"name":"Capsicum","quantity":1,"category":"Produce"},{"name":"Onion","quantity":1,"category":"Produce"},{"name":"Yoghurt","quantity":1,"category":"Dairy"},{"name":"Cucumber","quantity":1,"category":"Produce"},{"name":"Flatbread","quantity":1,"category":"Bakery"}]},
    {"id":"r39","tag":"Regular","name":"Chicken Parma","description":"Crumbed chicken topped with ham and cheese","image":"https://images.unsplash.com/photo-1632778149955-e80f8ceca2e8?w=400&h=300&fit=crop&q=80","emoji":"\U0001f357","time":"35 min","steps":["Crumb chicken breast with flour, egg, breadcrumbs.","Pan-fry until golden on both sides.","Place on a tray, top with tomato sauce and ham.","Add mozzarella on top.","Bake at 200\u00b0C for 10 min until cheese melts.","Serve with salad or chips."],"ingredients":[{"name":"Chicken Breast","quantity":2,"category":"Meat"},{"name":"Ham","quantity":1,"category":"Meat"},{"name":"Mozzarella","quantity":1,"category":"Dairy"},{"name":"Tomato Sauce","quantity":1,"category":"Pantry"},{"name":"Breadcrumbs","quantity":1,"category":"Pantry"},{"name":"Eggs","quantity":1,"category":"Dairy"}]},
    {"id":"r40","tag":"Regular","name":"Sausage Rolls","description":"Homemade pork sausage rolls","image":"https://images.unsplash.com/photo-1621996346565-e3dbc646d9a9?w=400&h=300&fit=crop&q=80","emoji":"\U0001f956","time":"35 min","steps":["Mix sausage meat with diced onion and herbs.","Lay out puff pastry sheets.","Place sausage mixture along one edge, roll up.","Cut into individual rolls, brush with egg wash.","Bake at 200\u00b0C for 25 min until golden.","Serve with tomato sauce."],"ingredients":[{"name":"Sausage Meat","quantity":1,"category":"Meat"},{"name":"Puff Pastry","quantity":1,"category":"Frozen"},{"name":"Onion","quantity":1,"category":"Produce"},{"name":"Eggs","quantity":1,"category":"Dairy"},{"name":"Tomato Sauce","quantity":1,"category":"Pantry"}]},
    {"id":"r41","tag":"Regular","name":"Pad Thai","description":"Thai stir-fried noodles with chicken","image":"https://images.unsplash.com/photo-1559314809-0d155014e29e?w=400&h=300&fit=crop&q=80","emoji":"\U0001f35c","time":"25 min","steps":["Soak rice noodles in hot water 5 min, drain.","Stir-fry sliced chicken until cooked.","Push to one side, scramble eggs.","Add noodles, soy sauce, lime juice, and sugar.","Toss everything together.","Top with peanuts and bean sprouts."],"ingredients":[{"name":"Rice Noodles","quantity":1,"category":"Pantry"},{"name":"Chicken Thigh","quantity":2,"category":"Meat"},{"name":"Eggs","quantity":2,"category":"Dairy"},{"name":"Peanuts","quantity":1,"category":"Pantry"},{"name":"Bean Sprouts","quantity":1,"category":"Produce"},{"name":"Lime","quantity":1,"category":"Produce"},{"name":"Soy Sauce","quantity":1,"category":"Pantry"}]},
