    {"id":"r47","tag":"Regular","name":"Pork Dumplings","description":"Pan-fried pork gyoza with dipping sauce","image":"https://images.unsplash.com/photo-1534080564583-6be75777b70a?w=400&h=300&fit=crop&q=80","emoji":"\U0001f95f","time":"35 min","steps":["Mix pork mince with ginger, garlic, soy sauce, spring onion.","Place filling in wrappers, fold and seal.","Pan-fry in oil until bottoms are golden.","Add water, cover and steam 5 min.","Mix soy sauce, vinegar, sesame oil for dipping.","Serve hot with dipping sauce."],"ingredients":[{"name":"Pork Mince","quantity":1,"category":"Meat"},{"name":"Dumpling Wrappers","quantity":1,"category":"Pantry"},{"name":"Ginger","quantity":1,"category":"Produce"},{"name":"Garlic","quantity":2,"category":"Produce"},{"name":"Soy Sauce","quantity":1,"category":"Pantry"},{"name":"Spring Onion","quantity":1,"category":"Produce"}]},
    {"id":"r48","tag":"Regular","name":"Roast Chicken","description":"Whole roast chicken with roast vegetables","image":"https://images.unsplash.com/photo-1598103442097-8b74394b95c6?w=400&h=300&fit=crop&q=80","emoji":"\U0001f357","time":"75 min","steps":["Preheat oven to 200\u00b0C.","Rub chicken with oil, salt, and herbs.","Place in roasting pan with potatoes and kumara.","Roast 60 min, basting halfway.","Check chicken is cooked (juices run clear).","Rest 10 min, carve and serve."],"ingredients":[{"name":"Whole Chicken","quantity":1,"category":"Meat"},{"name":"Potatoes","quantity":4,"category":"Produce"},{"name":"Kumara","quantity":2,"category":"Produce"},{"name":"Olive Oil","quantity":1,"category":"Pantry"},{"name":"Garlic","quantity":3,"category":"Produce"},{"name":"Rosemary","quantity":1,"category":"Produce"}]},
