    {"id":"v01","tag":"Vegetarian","name":"Veggie Pasta Bake","description":"Cheesy baked pasta with roasted vegetables","image":"https://images.unsplash.com/photo-1621996346565-e3dbc646d9a9?w=400&h=300&fit=crop&q=80","emoji":"\U0001f35d","time":"40 min","steps":["Cook penne until al dente.","Roast zucchini, capsicum, and mushrooms.","Mix pasta with veggies and canned tomatoes.","Pour into baking dish, top with mozzarella.","Bake at 190\u00b0C for 15 min.","Serve hot."],"ingredients":[{"name":"Penne","quantity":1,"category":"Pantry"},{"name":"Canned Tomatoes","quantity":1,"category":"Pantry"},{"name":"Mozzarella","quantity":1,"category":"Dairy"},{"name":"Zucchini","quantity":1,"category":"Produce"},{"name":"Capsicum","quantity":1,"category":"Produce"},{"name":"Mushrooms","quantity":1,"category":"Produce"}]},
    {"id":"v02","tag":"Vegetarian","name":"Tofu Stir Fry","description":"Crispy tofu with veggies and soy","image":"https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=400&h=300&fit=crop&q=80","emoji":"\U0001f958","time":"20 min","steps":["Press tofu and cut into cubes.","Pan-fry tofu until golden and crispy.","Stir-fry broccoli and capsicum.","Add garlic, ginger, and soy sauce.","Return tofu, toss together.","Serve over steamed rice."],"ingredients":[{"name":"Firm Tofu","quantity":1,"category":"Produce"},{"name":"Broccoli","quantity":1,"category":"Produce"},{"name":"Capsicum","quantity":1,"category":"Produce"},{"name":"Soy Sauce","quantity":1,"category":"Pantry"},{"name":"Rice","quantity":1,"category":"Pantry"},{"name":"Garlic","quantity":2,"category":"Produce"}]},
