    {"id":"v43","tag":"Vegetarian","name":"Cauliflower Cheese","description":"Baked cauliflower in cheese sauce","image":"https://images.unsplash.com/photo-1543339494-b4cd4f7ba686?w=400&h=300&fit=crop&q=80","emoji":"\U0001f9c0","time":"35 min","steps":["Cut cauliflower into florets, steam until tender.","Make cheese sauce: butter, flour, milk, cheese.","Place cauliflower in dish.","Pour cheese sauce over.","Top with breadcrumbs.","Bake at 190\u00b0C for 15 min."],"ingredients":[{"name":"Cauliflower","quantity":1,"category":"Produce"},{"name":"Cheese","quantity":2,"category":"Dairy"},{"name":"Milk","quantity":1,"category":"Dairy"},{"name":"Butter","quantity":1,"category":"Dairy"},{"name":"Flour","quantity":1,"category":"Pantry"},{"name":"Breadcrumbs","quantity":1,"category":"Pantry"}]},
