    {"id":"v47","tag":"Vegetarian","name":"Potato & Leek Soup","description":"Creamy potato and leek soup","image":"https://images.unsplash.com/photo-1476718406336-bb5a9690ee2a?w=400&h=300&fit=crop&q=80","emoji":"\U0001f35c","time":"35 min","steps":["Slice leeks and dice potatoes.","Saut\u00e9 leeks in butter until soft.","Add potatoes and stock.","Simmer 20 min until potatoes are tender.","Blend until smooth.","Stir in cream, serve with bread."],"ingredients":[{"name":"Potatoes","quantity":4,"category":"Produce"},{"name":"Leek","quantity":2,"category":"Produce"},{"name":"Vegetable Stock","quantity":1,"category":"Pantry"},{"name":"Cream","quantity":1,"category":"Dairy"},{"name":"Butter","quantity":1,"category":"Dairy"},{"name":"Bread","quantity":1,"category":"Bakery"}]},
